    public function __construct(private readonly MessageBusInterface $commandBus)
    {
        parent::__construct();
    }

    protected function execute(InputInterface $input, OutputInterface $output): int
    {
        $io = new SymfonyStyle($input, $output);
        $io->title('Seeding Siroko products');

        $created = 0;
        $indexed = 0;
        $errors = 0;

        foreach (self::PRODUCTS as $data) {
            try {
                $command = new CreateProductCommand($data['name'], $data['semanticDescription']);
                $this->commandBus->dispatch($command);
                ++$created;

                $this->commandBus->dispatch(new IndexProductCommand($command->id));
                ++$indexed;
            } catch (\Throwable $e) {
                ++$errors;
                $io->error(sprintf('[%s] %s', $data['name'], $e->getMessage()));
            }
        }

        $io->success(sprintf('Creados: %d | Indexados: %d | Errores: %d', $created, $indexed, $errors));

        return Command::SUCCESS;
    }
}
